// frontend/src/components/Navbar/Navbar.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Navbar = ({ activeMenu, setActiveMenu, isAuthenticated, handleLogout, userRole }) => {
    const navigate = useNavigate();
    const [hoveredMenu, setHoveredMenu] = useState(null);

    const navigateTo = (path, menuId) => {
        if (setActiveMenu) setActiveMenu(menuId);
        navigate(path);
    };

    const getMenuStyle = (menuId) => ({
        background: 'none',
        border: 'none',
        color: hoveredMenu === menuId ? '#ea580c' : '#fff',
        fontWeight: '700',
        cursor: 'pointer',
        fontSize: '14px',
        transition: 'color 0.3s ease'
    });

    return (
        <nav style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '20px 5%', background: '#0c0a09', borderBottom: '1px solid #262626', position: 'relative' }}>
            <div onClick={() => navigateTo('/', 'home')} style={{ cursor: 'pointer' }}>
                <h2 style={{ color: '#fef3c7', margin: 0, fontSize: '20px' }}>PasukanYerusSolo</h2>
            </div>

            <div className="nav-menu" style={{ display: 'flex', gap: '25px' }}>
                <button onClick={() => navigateTo('/', 'home')}>Beranda</button>
                <button onClick={() => navigateTo('/eksplorasi', 'lowongan')}>Lowongan</button>

                {/* LOGIKA MENU HRD */}
                {isAuthenticated && userRole === 'HRD' && (
                    <>
                        <button onClick={() => navigateTo('/hrd/dashboard', 'dashboard')}>Dashboard</button>
                        <button onClick={() => navigateTo('/hrd/branding', 'branding')}>Branding</button>
                    </>
                )}
            </div>

            <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                {isAuthenticated ? (
                    <button onClick={handleLogout} style={{ padding: '6px 16px', borderRadius: '20px', border: '1px solid #ef4444', color: '#ef4444', cursor: 'pointer', background: 'transparent' }}>Keluar</button>
                ) : (
                    <button 
                        onClick={() => navigate('/login')} 
                        style={{ 
                            padding: '6px 16px', borderRadius: '20px', 
                            border: '1px solid #ea580c', 
                            background: hoveredMenu === 'login' ? '#ea580c' : 'transparent', 
                            color: hoveredMenu === 'login' ? '#fff' : '#ea580c', 
                            fontWeight: '700', fontSize: '12px', cursor: 'pointer', transition: '0.3s' 
                        }}
                        onMouseEnter={() => setHoveredMenu('login')}
                        onMouseLeave={() => setHoveredMenu(null)}
                    >Login</button>
                )}
            </div>
            <style>{`@media (max-width: 768px) { .nav-menu { display: none !important; } }`}</style>
        </nav>
    );
};

export default Navbar;
